<template>
  <section class="admin-course-manager">
    <div class="admin-course-manager__head"><div><p class="admin-course-manager__eyebrow">AITOLEARN / CURSOS</p></div><q-btn unelevated no-caps class="admin-course-manager__primary" icon="mdi-plus" label="Novo curso" @click="openCreate" /></div>
    <div class="admin-course-manager__filters"><q-input v-model="search" outlined dense clearable label="Buscar curso" @keyup.enter="load"><template #prepend><q-icon name="mdi-magnify" /></template></q-input><q-btn flat round icon="mdi-refresh" aria-label="Atualizar cursos" :loading="loading" @click="load" /></div>
    <q-table flat bordered wrap-cells row-key="_id" class="admin-course-manager__table" :rows="courses" :columns="columns" :loading="loading" no-data-label="Nenhum curso cadastrado"><template #body-cell-title="props"><q-td :props="props"><div class="admin-course-manager__title"><img v-if="props.row.logo" :src="props.row.logo.url" alt="" /><span><strong>{{ props.row.title }}</strong><small>{{ props.row.slug }}</small></span></div></q-td></template><template #body-cell-price="props"><q-td :props="props">{{ money(props.row.price) }}</q-td></template><template #body-cell-published="props"><q-td :props="props"><q-icon :name="props.row.published ? 'mdi-eye-check-outline' : 'mdi-eye-off-outline'" :color="props.row.published ? 'positive' : 'grey'" /></q-td></template><template #body-cell-actions="props"><q-td :props="props"><q-btn flat round dense icon="mdi-pencil" aria-label="Editar curso" @click="openEdit(props.row)" /><q-btn flat round dense icon="mdi-format-list-bulleted" aria-label="Gerenciar aulas" @click="openTopics(props.row)" /><a class="admin-course-manager__preview" :href="courseUrl(props.row)" target="_blank" rel="noopener noreferrer" aria-label="Abrir landing do curso"><q-icon name="mdi-open-in-new" /></a><q-btn flat round dense color="negative" icon="mdi-delete-outline" aria-label="Excluir curso" @click="remove(props.row)" /></q-td></template></q-table>

    <q-dialog persistent v-model="dialog"><q-card class="admin-course-manager__dialog"><q-card-section class="admin-course-manager__dialog-head"><div><p class="admin-course-manager__eyebrow">Curso</p><h3>{{ form._id ? 'Editar curso' : 'Novo curso' }}</h3></div><q-btn flat round dense icon="mdi-close" aria-label="Fechar" @click="dialog = false" /></q-card-section><q-card-section><q-form @submit.prevent="save"><q-input v-model="form.title" outlined label="Titulo" :rules="[requiredRule]" /><q-input v-model="form.slug" outlined label="Slug publico" hint="Usado na URL da landing do curso" class="q-mt-sm" /><div class="admin-course-manager__form-grid"><q-input v-model.number="form.price" outlined type="number" min="0" step="0.01" label="Preco em real" /><q-input v-model.number="form.hours" outlined type="number" min="0" step="0.5" label="Carga horaria" /></div><q-select v-model="form.accessMode" outlined emit-value map-options :options="accessModeOptions" label="Tipo de acesso" class="q-mt-sm" /><q-input v-model="form.welcomeVideoUrl" outlined label="Link do video de boas-vindas" class="q-mt-sm" /><q-input v-model="form.description" outlined type="textarea" autogrow label="Descricao" class="q-mt-sm" /><div class="admin-course-manager__form-grid"><q-file v-model="form.logo" outlined label="Logo" accept="image/*"><template #prepend><q-icon name="mdi-image-outline" /></template></q-file><q-file v-model="form.banner" outlined label="Banner" accept="image/*"><template #prepend><q-icon name="mdi-panorama-outline" /></template></q-file></div><q-file v-model="form.attachments" outlined multiple label="Anexos do curso" accept="image/*,.pdf,.doc,.docx,.xls,.xlsx,.csv" class="q-mt-sm"><template #prepend><q-icon name="mdi-paperclip" /></template></q-file><q-toggle v-model="form.published" label="Publicar no marketplace" color="positive" class="q-mt-sm" /><q-btn unelevated no-caps class="admin-course-manager__primary full-width q-mt-md" type="submit" label="Salvar curso" :loading="saving" /></q-form></q-card-section></q-card></q-dialog>

    <q-dialog persistent v-model="topicsDialog"><q-card class="admin-course-manager__dialog admin-course-manager__dialog--wide"><q-card-section class="admin-course-manager__dialog-head"><div><p class="admin-course-manager__eyebrow">Aulas</p><h3>{{ selectedCourse.title }}</h3></div><q-btn flat round dense icon="mdi-close" aria-label="Fechar" @click="topicsDialog = false" /></q-card-section><q-card-section><div class="admin-course-manager__topic-tools"><q-input v-model="topicSearch" outlined dense clearable label="Buscar aula"><template #prepend><q-icon name="mdi-magnify" /></template></q-input><q-btn unelevated no-caps class="admin-course-manager__primary" icon="mdi-plus" label="Nova aula" @click="openTopicCreate" /></div><div class="admin-course-manager__topics"><article v-for="topic in filteredTopics" :key="topic._id" class="admin-course-manager__topic"><span>{{ String(topic.position + 1).padStart(2, '0') }}</span><div><strong>{{ topic.title }}</strong><small>{{ topic.lessonUrl }}</small></div><div><q-btn flat round dense icon="mdi-pencil" aria-label="Editar aula" @click="openTopicEdit(topic)" /><q-btn flat round dense color="negative" icon="mdi-delete-outline" aria-label="Excluir aula" @click="removeTopic(topic)" /></div></article><span v-if="!filteredTopics.length" class="admin-course-manager__empty">Nenhuma aula encontrada.</span></div></q-card-section></q-card></q-dialog>
    <q-dialog persistent v-model="topicDialog"><q-card class="admin-course-manager__dialog"><q-card-section class="admin-course-manager__dialog-head"><div><p class="admin-course-manager__eyebrow">Aula</p><h3>{{ topicForm._id ? 'Editar aula' : 'Nova aula' }}</h3></div><q-btn flat round dense icon="mdi-close" aria-label="Fechar" @click="topicDialog = false" /></q-card-section><q-card-section><q-form @submit.prevent="saveTopic"><q-input v-model="topicForm.title" outlined label="Titulo" :rules="[requiredRule]" /><q-input v-model="topicForm.lessonUrl" outlined label="Link da aula" class="q-mt-sm" :rules="[requiredRule]" /><q-input v-model="topicForm.notes" outlined type="textarea" autogrow label="Anotacoes" class="q-mt-sm" /><q-input v-model.number="topicForm.position" outlined type="number" min="0" label="Ordem" class="q-mt-sm" /><q-toggle v-model="topicForm.published" label="Aula publicada" color="positive" class="q-mt-sm" /><q-btn unelevated no-caps class="admin-course-manager__primary full-width q-mt-md" type="submit" label="Salvar aula" :loading="saving" /></q-form></q-card-section></q-card></q-dialog>
  </section>
</template>

<script setup>
import { computed, onMounted, ref } from 'vue'
import { useQuasar } from 'quasar'
import { api } from 'boot/axios'
const $q = useQuasar(); const token = localStorage.getItem('aito_admin_token'); const headers = { headers: { Authorization: `Bearer ${token}` } }; const courses = ref([]); const loading = ref(false); const saving = ref(false); const search = ref(''); const dialog = ref(false); const topicsDialog = ref(false); const topicDialog = ref(false); const topicSearch = ref(''); const selectedCourse = ref({}); const topics = ref([]); const form = ref(emptyCourse()); const topicForm = ref(emptyTopic())
const columns = [{ name: 'title', label: 'Curso', field: 'title', align: 'left' }, { name: 'price', label: 'Preco', field: 'price', align: 'right' }, { name: 'hours', label: 'Horas', field: 'hours', align: 'right' }, { name: 'topicCount', label: 'Aulas', field: 'topicCount', align: 'right' }, { name: 'purchaseCount', label: 'Compras', field: 'purchaseCount', align: 'right' }, { name: 'published', label: 'Publicado', field: 'published', align: 'center' }, { name: 'actions', label: '', align: 'right' }]
const accessModeOptions = [{ label: 'Acesso completo', value: 'full' }, { label: 'Acesso antecipado', value: 'early_access' }]
const filteredTopics = computed(() => topics.value.filter((topic) => !topicSearch.value || topic.title.toLowerCase().includes(topicSearch.value.toLowerCase())))
function emptyCourse() { return { _id: '', title: '', slug: '', price: 0, hours: 0, accessMode: 'full', welcomeVideoUrl: '', description: '', logo: null, banner: null, attachments: [], published: true } }
function emptyTopic() { return { _id: '', title: '', lessonUrl: '', notes: '', position: 0, published: true } }
function requiredRule(value) { return Boolean(String(value || '').trim()) || 'Preencha este campo.' }
function money(value) { return Number(value || 0) ? new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(Number(value)) : 'Gratuito' }
function selectedFile(value) { return value?.item ? value.item(0) : Array.isArray(value) ? value[0] : value }
function selectedFiles(value) { return Array.isArray(value) ? value : value ? Array.from(value) : [] }
async function load() { loading.value = true; try { const response = await api.get('/admin/courses', { ...headers, params: { q: search.value } }); courses.value = response.data.data || [] } catch (error) { notify(error) } finally { loading.value = false } }
function openCreate() { form.value = emptyCourse(); dialog.value = true }
function openEdit(item) { form.value = { ...emptyCourse(), ...item, logo: null, banner: null, attachments: [] }; dialog.value = true }
function courseUrl(course) { return `${window.location.origin}/cursos/${course.slug}` }
async function save() { saving.value = true; try { const body = new FormData(); ['title', 'slug', 'price', 'hours', 'accessMode', 'welcomeVideoUrl', 'description', 'published'].forEach((key) => body.append(key, form.value[key] ?? '')); const logo = selectedFile(form.value.logo); const banner = selectedFile(form.value.banner); if (logo) body.append('logo', logo); if (banner) body.append('banner', banner); selectedFiles(form.value.attachments).forEach((item) => body.append('attachments', item)); const endpoint = form.value._id ? `/admin/courses/${form.value._id}` : '/admin/courses'; const config = { headers: headers.headers }; const response = form.value._id ? await api.put(endpoint, body, config) : await api.post(endpoint, body, config); if (form.value._id) courses.value = courses.value.map((item) => item._id === form.value._id ? response.data.data : item); else courses.value.unshift(response.data.data); dialog.value = false; $q.notify({ type: 'positive', message: 'Curso salvo.' }) } catch (error) { notify(error) } finally { saving.value = false } }
function remove(item) { $q.dialog({ title: 'Excluir curso', message: `Remover ${item.title} e suas aulas?`, cancel: true, persistent: true }).onOk(async () => { try { await api.delete(`/admin/courses/${item._id}`, headers); courses.value = courses.value.filter((course) => course._id !== item._id); $q.notify({ type: 'positive', message: 'Curso removido.' }) } catch (error) { notify(error) } }) }
async function openTopics(course) { selectedCourse.value = course; topicSearch.value = ''; topicsDialog.value = true; await loadTopics() }
async function loadTopics() { try { const response = await api.get(`/admin/courses/${selectedCourse.value._id}/topics`, headers); topics.value = response.data.data || [] } catch (error) { notify(error) } }
function openTopicCreate() { topicForm.value = { ...emptyTopic(), position: topics.value.length }; topicDialog.value = true }
function openTopicEdit(topic) { topicForm.value = { ...emptyTopic(), ...topic }; topicDialog.value = true }
async function saveTopic() { saving.value = true; try { const endpoint = topicForm.value._id ? `/admin/courses/${selectedCourse.value._id}/topics/${topicForm.value._id}` : `/admin/courses/${selectedCourse.value._id}/topics`; const response = topicForm.value._id ? await api.put(endpoint, topicForm.value, headers) : await api.post(endpoint, topicForm.value, headers); if (topicForm.value._id) topics.value = topics.value.map((item) => item._id === topicForm.value._id ? response.data.data : item); else topics.value.push(response.data.data); topicDialog.value = false; $q.notify({ type: 'positive', message: 'Aula salva.' }); load() } catch (error) { notify(error) } finally { saving.value = false } }
function removeTopic(topic) { $q.dialog({ title: 'Excluir aula', message: `Remover ${topic.title}?`, cancel: true, persistent: true }).onOk(async () => { try { await api.delete(`/admin/courses/${selectedCourse.value._id}/topics/${topic._id}`, headers); topics.value = topics.value.filter((item) => item._id !== topic._id); $q.notify({ type: 'positive', message: 'Aula removida.' }); load() } catch (error) { notify(error) } }) }
function notify(error) { $q.notify({ type: 'negative', message: error.response?.data?.message || 'Nao foi possivel concluir.' }) }
onMounted(load)
</script>

<style scoped>.admin-course-manager{display:grid;gap:1rem;color:#effffb}.admin-course-manager__head{display:flex;align-items:flex-end;justify-content:space-between;gap:1rem}.admin-course-manager__eyebrow{margin:0;color:#8fffee;font-size:.65rem;font-weight:900;letter-spacing:.15em;text-transform:uppercase}.admin-course-manager h2{margin:.5rem 0 0;font-size:clamp(1.6rem,3vw,2.8rem)}.admin-course-manager__head span{color:rgba(229,255,250,.6);font-size:.75rem}.admin-course-manager__primary{color:#03110f;background:linear-gradient(135deg,#8fffee,#13bc9d);font-weight:900}.admin-course-manager__filters{display:flex;gap:.6rem}.admin-course-manager__filters :deep(.q-field){flex:1}.admin-course-manager__filters :deep(.q-field__control),.admin-course-manager__dialog :deep(.q-field__control){color:#effffb;background:rgba(7,40,40,.74)}.admin-course-manager__filters :deep(.q-field__native),.admin-course-manager__filters :deep(.q-field__label),.admin-course-manager__dialog :deep(.q-field__native),.admin-course-manager__dialog :deep(.q-field__label){color:rgba(239,255,251,.8)}.admin-course-manager__table{color:#effffb;background:rgba(3,16,18,.58);border-color:rgba(19,188,157,.2)}.admin-course-manager__table :deep(th){color:#8fffee;font-size:.68rem}.admin-course-manager__table :deep(td){color:rgba(239,255,251,.78);font-size:.72rem}.admin-course-manager__title{display:flex;align-items:center;gap:.5rem}.admin-course-manager__title img{width:30px;height:30px;border-radius:.3rem;object-fit:contain;background:rgba(19,188,157,.12)}.admin-course-manager__dialog{width:min(94vw,660px);color:#effffb;background:#061819;border:1px solid rgba(19,188,157,.3)}.admin-course-manager__dialog--wide{width:min(94vw,800px)}.admin-course-manager__dialog-head{display:flex;justify-content:space-between;gap:.8rem}.admin-course-manager__dialog h3{margin:.4rem 0 0}.admin-course-manager__form-grid{display:grid;grid-template-columns:1fr 1fr;gap:.6rem;margin-top:.6rem}.admin-course-manager__topic-tools{display:flex;gap:.6rem}.admin-course-manager__topic-tools :deep(.q-field){flex:1}.admin-course-manager__topics{display:grid;gap:.5rem;margin-top:1rem}.admin-course-manager__topic{display:grid;grid-template-columns:2rem 1fr auto;gap:.5rem;align-items:center;padding:.7rem;border:1px solid rgba(19,188,157,.18);border-radius:.5rem}.admin-course-manager__topic>span{color:#50dcc4}.admin-course-manager__topic div:nth-child(2){display:grid;gap:.25rem}.admin-course-manager__topic small{overflow:hidden;color:rgba(239,255,251,.52);font-size:.65rem;text-overflow:ellipsis;white-space:nowrap}.admin-course-manager__empty{padding:2rem;color:rgba(239,255,251,.58);text-align:center}@media(max-width:700px){.admin-course-manager__head{align-items:flex-start;flex-direction:column}.admin-course-manager__head .q-btn{width:100%}.admin-course-manager__form-grid{grid-template-columns:1fr}.admin-course-manager__topic-tools{display:grid}.admin-course-manager__topic{grid-template-columns:1.5rem 1fr auto}}
.admin-course-manager__title>span{display:grid;gap:.15rem}.admin-course-manager__title small{color:rgba(239,255,251,.48);font-size:.62rem}.admin-course-manager__preview{display:inline-flex;align-items:center;justify-content:center;width:28px;height:28px;color:#8fffee;text-decoration:none}
</style>
